import React from 'react';

const Header = () => {
    return (
        <header className="bg-gray-800 text-white p-4">
            <nav className="flex justify-between items-center">
                <div className="text-lg font-bold">My Portfolio</div>
                <ul className="flex flex-row space-x-4">
                    <li>
                        <a href="#about" className="px-4 py-2 bg-blue-600 rounded hover:bg-blue-700 transition">About</a>
                    </li>
                    <li>
                        <a href="#skills" className="px-4 py-2 bg-blue-600 rounded hover:bg-blue-700 transition">Skills</a>
                    </li>
                    <li>
                        <a href="#projects" className="px-4 py-2 bg-blue-600 rounded hover:bg-blue-700 transition">Projects</a>
                    </li>
                    <li>
                        <a href="#contact" className="px-4 py-2 bg-blue-600 rounded hover:bg-blue-700 transition">Contact</a>
                    </li>
                </ul>
            </nav>
        </header>
    );
};

export default Header;
